const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const config = body.config || {};

if (!tenantId || !automationId) {
  return [{ json: { valid: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, config, valid: true } }];

const catalogRow = $('04. Chercher catalogue + tenant').first().json;
const existingPurchase = $('05. Verifier achat existant').first().json;
const data = $('02. Valider donnees').first().json;

if (!catalogRow || !catalogRow.code) {
  return [{ json: { valid: false, error: 'Automatisation ou tenant introuvable' } }];
}

const tenantName = catalogRow.tenant_name || 'Client';
const automationCode = catalogRow.code;
const automationNom = catalogRow.nom;
const setupPrice = catalogRow.setup_price || 0;
const monthlyPrice = catalogRow.monthly_price || 0;

// Tag pour organiser dans n8n self-hosted
const clientTag = `client:${tenantName}`;
const existingWorkflowIds = existingPurchase?.n8n_workflow_ids || [];

// Construire le workflow a creer pour ce client
const workflow = {
  name: `[${tenantName}] ${automationNom}`,
  tags: [clientTag, 'talosprimes', `auto:${automationCode}`],
  nodes: [
    {
      parameters: {
        rule: { interval: [{ field: 'hours', hoursInterval: 24 }] }
      },
      id: 'schedule-node',
      name: 'Declencheur',
      type: 'n8n-nodes-base.scheduleTrigger',
      typeVersion: 1.2,
      position: [250, 300]
    },
    {
      parameters: {
        jsCode: `// Automatisation: ${automationNom}\n// Client: ${tenantName}\n// Code: ${automationCode}\n// Cree automatiquement par TalosPrimes\nconst now = new Date().toISOString();\nreturn [{ json: { client: '${tenantName}', automation: '${automationCode}', timestamp: now, status: 'ok' } }];`
      },
      id: 'code-node',
      name: 'Traitement',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [470, 300]
    }
  ],
  connections: {
    'Declencheur': { main: [[{ node: 'Traitement', type: 'main', index: 0 }]] }
  },
  settings: { executionOrder: 'v1' }
};

return [{ json: {
  valid: true,
  tenantId: data.tenantId,
  automationId: data.automationId,
  automationCode,
  automationNom,
  tenantName,
  setupPrice,
  monthlyPrice,
  config: data.config,
  clientTag,
  existingWorkflowIds,
  workflow
} }];

// Creer les tags s'ils n'existent pas deja
const data = $('06. Construire workflow').first().json;
const baseUrl = $env.N8N_API_URL || 'http://localhost:5678';
const apiKey = $env.N8N_API_KEY || '';
const tagsToCreate = [data.clientTag, 'talosprimes', `auto:${data.automationCode}`];
const tagIds = [];

for (const tagName of tagsToCreate) {
  try {
    // Essayer de creer le tag
    const createResp = await fetch(`${baseUrl}/api/v1/tags`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-N8N-API-KEY': apiKey },
      body: JSON.stringify({ name: tagName })
    });
    const createData = await createResp.json();
    if (createData.id) {
      tagIds.push({ id: createData.id, name: tagName });
    } else {
      // Tag existe deja, le chercher
      const listResp = await fetch(`${baseUrl}/api/v1/tags`, {
        headers: { 'X-N8N-API-KEY': apiKey }
      });
      const allTags = await listResp.json();
      const found = (allTags.data || allTags).find(t => t.name === tagName);
      if (found) tagIds.push({ id: found.id, name: tagName });
    }
  } catch (err) {
    // On continue meme si le tag echoue
  }
}

return [{ json: { ...data, tagIds } }];

// Creer le workflow avec les tags
const data = $input.first().json;
const baseUrl = $env.N8N_API_URL || 'http://localhost:5678';
const apiKey = $env.N8N_API_KEY || '';

// Ajouter les tag IDs au workflow
const workflow = data.workflow;
if (data.tagIds && data.tagIds.length > 0) {
  workflow.tags = data.tagIds.map(t => ({ id: t.id }));
}

try {
  const resp = await fetch(`${baseUrl}/api/v1/workflows`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-N8N-API-KEY': apiKey },
    body: JSON.stringify(workflow)
  });
  const result = await resp.json();
  const workflowId = result.id || null;
  const workflowName = result.name || null;

  // Fusionner le nouveau workflowId avec les existants
  const existingIds = data.existingWorkflowIds || [];
  const allWorkflowIds = workflowId ? [...existingIds, String(workflowId)] : existingIds;

  return [{ json: {
    success: !!workflowId,
    workflowId,
    workflowName,
    allWorkflowIds,
    tenantId: data.tenantId,
    automationId: data.automationId,
    automationCode: data.automationCode,
    automationNom: data.automationNom,
    tenantName: data.tenantName,
    setupPrice: data.setupPrice,
    monthlyPrice: data.monthlyPrice,
    config: data.config,
    clientTag: data.clientTag,
    error: workflowId ? null : 'Erreur creation workflow'
  } }];
} catch (err) {
  return [{ json: {
    success: false,
    workflowId: null,
    workflowName: null,
    allWorkflowIds: data.existingWorkflowIds || [],
    tenantId: data.tenantId,
    automationId: data.automationId,
    automationCode: data.automationCode,
    automationNom: data.automationNom,
    tenantName: data.tenantName,
    setupPrice: data.setupPrice,
    monthlyPrice: data.monthlyPrice,
    config: data.config,
    clientTag: data.clientTag,
    error: String(err)
  } }];
}

const data = $('09. Creer workflow via API').first().json;
const purchaseResult = $input.first().json;

return [{ json: {
  success: data.success,
  workflowId: data.workflowId,
  workflowName: data.workflowName,
  clientTag: data.clientTag,
  tenantId: data.tenantId,
  automationCode: data.automationCode,
  workflowIds: data.allWorkflowIds || [],
  purchaseId: purchaseResult.id || null,
  purchaseStatus: purchaseResult.status || 'active',
  message: data.success
    ? `Workflow "${data.workflowName}" cree et tagge "${data.clientTag}". Achat enregistre.`
    : data.error || 'Erreur lors de la creation du workflow'
} }];
